   728→                  onChange={(e) => setInput(e.target.value)}
   729→                  onKeyDown={handleKeyPress}
   730→                  placeholder={`Scrivi a ${characterProps?.name || 'Coach'}...`}
   731→                  className="flex-1 px-3 py-2 bg-slate-100 dark:bg-slate-800 rounded-xl border-0 focus:ring-2 focus:ring-accent-themed outline-none text-sm"
   732→                  disabled={isLoading}
   733→                />
   734→                <Button
   735→                  size="icon-sm"
   736→                  onClick={handleSend}
   737→                  disabled={!input.trim() || isLoading}
   738→                  className="bg-accent-themed hover:bg-accent-themed/90 flex-shrink-0"
   739→                >
   740→                  <Send className="h-4 w-4" />
   741→                </Button>
